import { useEffect, useState } from 'react';
import { format, addDays } from 'date-fns';
import { Video, Building2, Clock, Calendar as CalendarIcon } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Calendar } from '@/components/ui/calendar';
import { Badge } from '@/components/ui/badge';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { cn } from '@/lib/utils';
import { useBookingStore } from '@/store/bookingStore';
import { appointmentService } from '@/services/appointmentService';
import { TimeSlot } from '@/types';

export default function ScheduleStep() {
  const {
    selectedDoctor,
    consultationType,
    selectedDate,
    selectedTimeSlot,
    consultationFee,
    setConsultationType,
    setSchedule,
  } = useBookingStore();

  const [availableSlots, setAvailableSlots] = useState<TimeSlot[]>([]);
  const [isLoadingSlots, setIsLoadingSlots] = useState(false);
  const [calendarOpen, setCalendarOpen] = useState(false);

  useEffect(() => {
    if (selectedDoctor && selectedDate) {
      loadAvailableSlots();
    }
  }, [selectedDoctor, selectedDate]);

  const loadAvailableSlots = async () => {
    if (!selectedDoctor || !selectedDate) return;
    
    setIsLoadingSlots(true);
    const doctorUserId = selectedDoctor.userId ?? selectedDoctor.id;
    const response = await appointmentService.getAvailableSlots(doctorUserId, selectedDate);
    if (response.success) {
      setAvailableSlots(response.data);
    }
    setIsLoadingSlots(false);
  };

  const handleDateSelect = (date: Date | undefined) => {
    if (date) {
      const dateStr = format(date, 'yyyy-MM-dd');
      const fee = consultationType === 'online' 
        ? selectedDoctor?.onlineConsultationFee || 0
        : selectedDoctor?.consultationFee || 0;
      setSchedule(dateStr, selectedTimeSlot!, fee);
      setCalendarOpen(false);
    }
  };

  const handleSlotSelect = (slot: TimeSlot) => {
    const fee = consultationType === 'online' 
      ? selectedDoctor?.onlineConsultationFee || 0
      : selectedDoctor?.consultationFee || 0;
    setSchedule(selectedDate, slot, fee);
  };

  const handleConsultationTypeSelect = (type: 'online' | 'in-clinic') => {
    setConsultationType(type);
  };

  // Disable past dates, dates >30 days out, and days not in doctor's weekly_schedule
  const disabledDays = (() => {
    const schedule = selectedDoctor?.weeklySchedule;
    const base = { before: new Date(), after: addDays(new Date(), 30) };
    if (!schedule || Object.keys(schedule).length === 0) return base;

    const dayNameMap: Record<number, string> = {
      0: 'sunday', 1: 'monday', 2: 'tuesday', 3: 'wednesday',
      4: 'thursday', 5: 'friday', 6: 'saturday',
    };
    const activeDayNums = new Set(
      Object.keys(schedule).map((d) =>
        Object.entries(dayNameMap).find(([, name]) => name === d)?.[0]
      ).filter(Boolean).map(Number)
    );
    return [
      base,
      (date: Date) => !activeDayNums.has(date.getDay()),
    ];
  })();

  return (
    <div className="space-y-6">
      {/* Consultation Type */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">
            <Clock className="h-5 w-5 text-primary" />
            Consultation Type
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid sm:grid-cols-2 gap-4">
            <button
              onClick={() => handleConsultationTypeSelect('online')}
              className={cn(
                'p-4 rounded-xl border-2 transition-all text-left',
                consultationType === 'online'
                  ? 'border-primary bg-primary/5'
                  : 'border-border hover:border-primary/50'
              )}
            >
              <div className="flex items-start gap-3">
                <div className={cn(
                  'p-3 rounded-lg',
                  consultationType === 'online' ? 'bg-primary text-primary-foreground' : 'bg-secondary'
                )}>
                  <Video className="h-5 w-5" />
                </div>
                <div className="flex-1">
                  <h4 className="font-semibold text-foreground">Online Consultation</h4>
                  <p className="text-sm text-muted-foreground mt-1">
                    Video call from the comfort of your home
                  </p>
                  <p className="text-lg font-bold text-primary mt-2">
                    ₱{selectedDoctor?.onlineConsultationFee?.toLocaleString()}
                  </p>
                </div>
              </div>
            </button>

            <button
              onClick={() => handleConsultationTypeSelect('in-clinic')}
              className={cn(
                'p-4 rounded-xl border-2 transition-all text-left',
                consultationType === 'in-clinic'
                  ? 'border-primary bg-primary/5'
                  : 'border-border hover:border-primary/50'
              )}
            >
              <div className="flex items-start gap-3">
                <div className={cn(
                  'p-3 rounded-lg',
                  consultationType === 'in-clinic' ? 'bg-primary text-primary-foreground' : 'bg-secondary'
                )}>
                  <Building2 className="h-5 w-5" />
                </div>
                <div className="flex-1">
                  <h4 className="font-semibold text-foreground">In-Clinic Visit</h4>
                  <p className="text-sm text-muted-foreground mt-1">
                    Face-to-face consultation at {selectedDoctor?.hospital}
                  </p>
                  <p className="text-lg font-bold text-primary mt-2">
                    ₱{selectedDoctor?.consultationFee?.toLocaleString()}
                  </p>
                </div>
              </div>
            </button>
          </div>
        </CardContent>
      </Card>

      {/* Date Selection */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">
            <CalendarIcon className="h-5 w-5 text-primary" />
            Select Date
          </CardTitle>
        </CardHeader>
        <CardContent>
          <Popover open={calendarOpen} onOpenChange={setCalendarOpen}>
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                className={cn(
                  'w-full justify-start text-left font-normal h-12',
                  !selectedDate && 'text-muted-foreground'
                )}
              >
                <CalendarIcon className="mr-2 h-4 w-4" />
                {selectedDate ? format(new Date(selectedDate), 'EEEE, MMMM d, yyyy') : 'Pick a date'}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="start">
              <Calendar
                mode="single"
                selected={selectedDate ? new Date(selectedDate) : undefined}
                onSelect={handleDateSelect}
                disabled={disabledDays}
                initialFocus
              />
            </PopoverContent>
          </Popover>
        </CardContent>
      </Card>

      {/* Time Slots */}
      {selectedDate && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <Clock className="h-5 w-5 text-primary" />
              Available Time Slots
            </CardTitle>
          </CardHeader>
          <CardContent>
            {isLoadingSlots ? (
              <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
                {Array.from({ length: 12 }).map((_, i) => (
                  <div 
                    key={i}
                    className="h-10 rounded-lg bg-muted animate-pulse"
                  />
                ))}
              </div>
            ) : availableSlots.length === 0 ? (
              <p className="text-center text-muted-foreground py-4">
                {selectedDoctor?.weeklySchedule && Object.keys(selectedDoctor.weeklySchedule).length > 0
                  ? 'No available slots for this date'
                  : 'This doctor has not set up their schedule yet'}
              </p>
            ) : (
              <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
                {availableSlots.map((slot) => (
                  <Button
                    key={slot.id}
                    variant={selectedTimeSlot?.id === slot.id ? 'default' : 'outline'}
                    size="sm"
                    disabled={!slot.isAvailable}
                    onClick={() => slot.isAvailable && handleSlotSelect(slot)}
                    className={cn(
                      'h-10',
                      selectedTimeSlot?.id === slot.id && 'gradient-primary border-0',
                      !slot.isAvailable && 'opacity-50 cursor-not-allowed line-through'
                    )}
                  >
                    {slot.startTime}
                  </Button>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Summary */}
      {consultationType && selectedDate && selectedTimeSlot && (
        <Card className="border-primary/30 bg-primary/5">
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Selected Schedule</p>
                <p className="font-semibold text-foreground">
                  {format(new Date(selectedDate), 'MMM d, yyyy')} at {selectedTimeSlot.startTime}
                </p>
                <Badge variant="secondary" className="mt-1 capitalize">
                  {consultationType === 'online' ? '📹 Online' : '🏥 In-Clinic'}
                </Badge>
              </div>
              <div className="text-right">
                <p className="text-sm text-muted-foreground">Consultation Fee</p>
                <p className="text-2xl font-bold text-primary">
                  ₱{consultationFee.toLocaleString()}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}
